code = """import json, re, pandas as pd
from pathlib import Path

# Load large tool outputs
avg_path = Path(var_call_6cvJn0Z5Kyfbmt5yS27d0um0)
with avg_path.open() as f:
    avg_data = json.load(f)

books_path = Path(var_call_7HIZapPAwrfUyHlEaBlBv9ry)
with books_path.open() as f:
    books_data = json.load(f)

# Create DataFrames
avg_df = pd.DataFrame(avg_data)
books_df = pd.DataFrame(books_data)

# Normalize types
avg_df['avg_rating'] = avg_df['avg_rating'].astype(float)

# Extract publication year from details text
year_pattern = re.compile(r'(19|20)\d{2}')

def extract_year(text):
    if not isinstance(text, str):
        return None
    m = year_pattern.search(text)
    if m:
        return int(m.group(0))
    return None

books_df['year'] = books_df['details'].apply(extract_year)

# Derive decade label like '1980s'
books_df['decade'] = books_df['year'].apply(lambda y: f"{int(y//10*10)}s" if pd.notnull(y) else None)

# Fuzzy join on numeric id part (assumes ids like 'purchaseid_123', 'bookid_123')

def extract_num(s):
    if not isinstance(s, str):
        return None
    m = re.search(r'(\d+)$', s)
    return int(m.group(1)) if m else None

avg_df['id_num'] = avg_df['purchase_id'].apply(extract_num)
books_df['id_num'] = books_df['book_id'].apply(extract_num)

merged = pd.merge(avg_df, books_df[['book_id','decade','id_num']], on='id_num', how='inner')

# Filter to rows with a known decade
merged = merged[merged['decade'].notna()]

# Compute per-book average rating (already per purchase_id) and then per-decade stats
per_decade = merged.groupby('decade').agg(
    avg_rating_over_books=('avg_rating', 'mean'),
    distinct_books=('book_id', pd.Series.nunique)
).reset_index()

# Filter decades with at least 10 distinct books
eligible = per_decade[per_decade['distinct_books'] >= 10]

if eligible.empty:
    result = None
else:
    top_row = eligible.sort_values('avg_rating_over_books', ascending=False).iloc[0]
    result = {
        'decade': top_row['decade'],
        'average_rating': round(float(top_row['avg_rating_over_books']), 3),
        'distinct_books_count': int(top_row['distinct_books'])
    }

out = json.dumps(result)
print("__RESULT__:")
print(out)"""

